import React, { useState, useEffect, useCallback, useRef } from 'react';
import FeedList from '../components/feed/FeedList';
import CategoryTabs from '../components/feed/CategoryTabs';
import Navbar from '../components/common/Navbar';
import useFeed from '../hooks/useFeed';
import { useAuth } from '../context/AuthContext';

const Feed = () => {
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState('all');
  const [savedIds, setSavedIds] = useState(user?.savedArticles?.map(String) || []);
  const sentinelRef = useRef(null);

  const category = activeTab === 'all' ? '' : activeTab;
  const { feed, loading, error, hasMore, loadMore, reset } = useFeed(category);

  // Reset + initial load on category change
  useEffect(() => {
    reset();
    loadMore(true);
  }, [activeTab]); // eslint-disable-line

  // Auto-refresh feed every 30 seconds to pick up new articles
  useEffect(() => {
    const interval = setInterval(() => {
      reset();
      loadMore(true);
    }, 30000);
    return () => clearInterval(interval);
  }, [activeTab]); // eslint-disable-line

  // Infinite scroll sentinel
  useEffect(() => {
    const el = sentinelRef.current;
    if (!el) return;
    const observer = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting && hasMore && !loading) loadMore(); },
      { threshold: 0.1 }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, [hasMore, loading, loadMore]);

  const handleBookmarkToggle = useCallback((articleId) => {
    setSavedIds((prev) =>
      prev.includes(articleId) ? prev.filter((id) => id !== articleId) : [...prev, articleId]
    );
  }, []);

  return (
    <div style={styles.page}>
      <Navbar />
      <div style={styles.container}>
        <CategoryTabs active={activeTab} onChange={setActiveTab} />
        {error && <p style={styles.error}>{error}</p>}
        <FeedList
          feed={feed}
          loading={loading}
          hasMore={hasMore}
          savedIds={savedIds}
          onBookmarkToggle={handleBookmarkToggle}
        />
        {/* Invisible sentinel for infinite scroll */}
        <div ref={sentinelRef} style={{ height: 1 }} />
      </div>
    </div>
  );
};

const styles = {
  page: { minHeight: '100vh', background: '#f4f6fb' },
  container: { maxWidth: 680, margin: '0 auto', padding: '16px 16px 40px' },
  error: { color: '#e94560', textAlign: 'center', padding: 12 },
};

export default Feed;
